import{_ as t,o as a,c as r,ag as i}from"./chunks/framework.DXGyWiRo.js";const n="/images/lekt3406.jpg",l="/images/lekt3405.jpg",d="/images/lekt3403.jpg",o="/images/lekt3404.jpg",s="/images/lekt3402.jpg",u="/images/lekt3401.jpg",p="/images/lekt3407.jpg",z=JSON.parse('{"title":"Lektion 34","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/lektion34.md","filePath":"lektionen/lektion34.md"}'),h={name:"lektionen/lektion34.md"};function b(m,e,k,c,f,g){return a(),r("div",null,[...e[0]||(e[0]=[i('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="lektion-34" tabindex="-1">Lektion 34 <a class="header-anchor" href="#lektion-34" aria-label="Permalink to &quot;Lektion 34&quot;">​</a></h1><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><ul><li>34.1. Das Perfekt (लिट्)</li><li>34.2. Das reduplizierte Perfekt (द्वित्वलिट्) <ul><li>34.2.1. Stammabstufung</li><li>34.2.2. Die Perfektendungen</li><li>34.2.3. Bindevokal -i-</li><li>34.2.4. Reduplikation konsonantisch anlautender Wurzeln</li><li>34.2.5. Reduplikation vokalisch anlautender Wurzeln</li></ul></li><li>34.3. Typen des reduplizierten Perfekts</li><li>34.4. Perfekt Typ I: Perfekt ohne Stammabstufung</li><li>34.5. Perfekt II: starker Stamm Hochstufe, schwacher Stamm Tiefstufe</li><li>34.6. Wortliste</li><li>34.7. Übung</li><li>34.8. Übersetzungsübung</li></ul><h2 id="_34-1-das-perfekt-लिट्" tabindex="-1">34.1. Das Perfekt (लिट्) <a class="header-anchor" href="#_34-1-das-perfekt-लिट्" aria-label="Permalink to &quot;34.1. Das Perfekt (लिट्)&quot;">​</a></h2><p>Im klassischen Sanskrit gibt es vom Perfektstamm nur Indikativ und Partizip.</p><p>Es gibt zwei Arten der Perfektbildung:</p><ul><li>das reduplizierte Perfekt = द्वित्वलिट्</li><li>das periphrastische Perfekt = अनुप्रयोगलिट्</li></ul><p>Das periphrastische Perfekt (अनुप्रयोगलिट्) wird gebraucht:</p><ol><li><p>bei den abgeleiteten Konjugationen (Kausativ, Desiderativ, Frequentativ, Denominativa)</p></li><li><p>bei Wurzeln, die mit einem langen Vokal (außer ā-) beginnen, bzw. mit einem Vokal (außer a-) vor zwei Konsonanten</p></li><li><p>bei einigen sonstigen Wurzeln</p></li></ol><h2 id="_34-2-das-reduplizierte-perfekt-द्वित्वलिट्" tabindex="-1">34.2. Das reduplizierte Perfekt (द्वित्वलिट्) <a class="header-anchor" href="#_34-2-das-reduplizierte-perfekt-द्वित्वलिट्" aria-label="Permalink to &quot;34.2. Das reduplizierte Perfekt (द्वित्वलिट्)&quot;">​</a></h2><h3 id="_34-2-1-stammabstufung" tabindex="-1">34.2.1. Stammabstufung <a class="header-anchor" href="#_34-2-1-stammabstufung" aria-label="Permalink to &quot;34.2.1. Stammabstufung&quot;">​</a></h3><p>Bildung:</p><p>starker Stamm: Singular Parasmaipada</p><p>reduplizierte hochstufige bzw. dehnstufige Wurzel + Perfektendung</p><p>schwacher Stamm: alle übrigen Formen</p><p>reduplizierte tiefstufige Wurzel + Perfektendung</p><p>Generell (auch außerhalb des Perfekt) keine Stammabstufung haben Wurzeln der Form:</p><ul><li>(Konsonant)-Konsonant-Langvokal-Konsonant</li><li>(Konsonant)-Konsonant-Vokal-Konsonant-Konsonant</li></ul><p>Im Perfekt haben außerdem keine Stammabstufung Wurzeln der Form:</p><ul><li>a-Konsonant</li><li>ā-Konsonant</li></ul><h3 id="_34-2-2-die-perfektendungen" tabindex="-1">34.2.2. Die Perfektendungen <a class="header-anchor" href="#_34-2-2-die-perfektendungen" aria-label="Permalink to &quot;34.2.2. Die Perfektendungen&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th>3. Singular</th><th>3. Plural</th></tr></thead><tbody><tr><td>Parasmaipada</td><td>-a</td><td>-ur</td></tr><tr><td>Ātmanepada</td><td>-e</td><td>-re</td></tr></tbody></table><h3 id="_34-2-3-bindevokal-i" tabindex="-1">34.2.3. Bindevokal -i- <a class="header-anchor" href="#_34-2-3-bindevokal-i" aria-label="Permalink to &quot;34.2.3. Bindevokal -i-&quot;">​</a></h3><p>Vor die Endung der 3.pl.Ā (-re) tritt immer der Bindevokal -i-, vor die anderen konsonantisch anlautenden Endungen bei der Mehrzahl der Wurzeln.</p><h3 id="_34-2-4-reduplikation-konsonantisch-anlautender-wurzeln" tabindex="-1">34.2.4. Reduplikation konsonantisch anlautender Wurzeln <a class="header-anchor" href="#_34-2-4-reduplikation-konsonantisch-anlautender-wurzeln" aria-label="Permalink to &quot;34.2.4. Reduplikation konsonantisch anlautender Wurzeln&quot;">​</a></h3><p>Für die Reduplikation anlautender Konsonanten gelten die in <a href="./lektion33">Lektion 33</a> gegebenen Regeln.</p><p>Reduplikationsvokal bei konsonantisch anlautenden Wurzeln ist der kurze Wurzelvokal.</p><p>Diphtonge vor Konsonant werden durch den entsprechenden kurzen Tiefstufenvokal reduziert.</p><p>ṛ,  ṝ, ḷ, und auslautende Diphtonge werden durch -a- redupliziert.</p><p>Beispiele:</p><blockquote><table tabindex="0"><thead><tr><th>Wurzel</th><th>3.sg.Perf.P</th></tr></thead><tbody><tr><td>भिद्</td><td></td></tr><tr><td>बिभेद</td><td></td></tr></tbody></table><p>| | मुच् |</p><p>मुमोच</p><p>| | भृ | बभार |</p></blockquote><p>Einige mit y- bzw. v- anlautende Wurzeln reduplizieren mit i- bzw. u-, das in den schwachen Formen mit dem Wurzelvokal &quot;verschmilzt&quot;.</p><p>Beispiele:</p><blockquote><table tabindex="0"><thead><tr><th>Wurzel</th><th>3.sg.Perf.P</th><th>3.pl.Perf.P</th></tr></thead><tbody><tr><td>वच्</td><td>उवाच</td><td></td></tr><tr><td>u-vāc-a</td><td>ऊचुर्</td><td></td></tr><tr><td>u + uc-ur</td><td></td><td></td></tr><tr><td>यज्</td><td>इयाज</td><td></td></tr><tr><td>i-yāj-a</td><td>ईजुर्</td><td></td></tr><tr><td>i + ij-ur</td><td></td><td></td></tr></tbody></table></blockquote><h3 id="_34-2-5-reduplikation-vokalisch-anlautender-wurzeln" tabindex="-1">34.2.5. Reduplikation vokalisch anlautender Wurzeln <a class="header-anchor" href="#_34-2-5-reduplikation-vokalisch-anlautender-wurzeln" aria-label="Permalink to &quot;34.2.5. Reduplikation vokalisch anlautender Wurzeln&quot;">​</a></h3><p>1. anlautendes a-, ā- wird mit a- redupliziert, sodass ā- erscheint.</p><p>Beispiele:</p><blockquote><table tabindex="0"><thead><tr><th>Wurzel</th><th>3.sg.Perf.P</th></tr></thead><tbody><tr><td>अस् 2 &quot;sein&quot; und अस् 4 &quot;werfen&quot;</td><td></td></tr><tr><td>आस</td><td></td></tr><tr><td>a + as-a</td><td></td></tr></tbody></table><p>|</p></blockquote><ol start="2"><li>Wurzeln mit anlautendem i- haben als Reduplikationssilbe im starken Stamm iy-, im schwachen Stamm i-, das mit dem Wurzelvokal zu ī- &quot;verschmilzt. Analoges gilt für anlautendes u-.</li></ol><p>Beispiele:</p><blockquote><table tabindex="0"><thead><tr><th>Wurzel</th><th>3.sg.Perf.P</th><th>3.pl.Perf.P</th></tr></thead><tbody><tr><td>इ</td><td></td><td></td></tr><tr><td>इयाय</td><td></td><td></td></tr><tr><td>iy + ai + a</td><td></td><td></td></tr></tbody></table><p>| ईयुर्<br> i + iy-ur | | इष् | इयेष<br> iy-eṣ-a | ईषुर्<br> i + iṣ-ur |</p></blockquote><p>3. Wurzeln die mit a- vor zwei Konsonanten oder mit ṛ- anlauten, haben als Reduplikationssilbe ān-</p><p>Beispiele:</p><blockquote><table tabindex="0"><thead><tr><th>Wurzel</th><th>3.sg.Perf.P</th><th>3.pl.Perf.P</th></tr></thead><tbody><tr><td>अञ्ज्</td><td>आनञ्ज</td><td>आनञ्जुर्</td></tr><tr><td>ऋध्</td><td>आनर्ध</td><td>आनृधुर्</td></tr></tbody></table></blockquote><h2 id="_34-3-typen-des-reduplizierten-perfekts" tabindex="-1">34.3. Typen des reduplizierten Perfekts <a class="header-anchor" href="#_34-3-typen-des-reduplizierten-perfekts" aria-label="Permalink to &quot;34.3. Typen des reduplizierten Perfekts&quot;">​</a></h2><p>Einteilungsprinzip: Besonderheiten der Stammabstufung:</p><ul><li>Perfekt ohne Stammabstufung: Typ I</li><li>Perfekt mit Stammabstufung: Typ II - V</li><li>unregelmäßige Perfektbildungen</li></ul><h2 id="_34-4-perfekt-typ-i-perfekt-ohne-stammabstufung" tabindex="-1">34.4. Perfekt Typ I: Perfekt ohne Stammabstufung <a class="header-anchor" href="#_34-4-perfekt-typ-i-perfekt-ohne-stammabstufung" aria-label="Permalink to &quot;34.4. Perfekt Typ I: Perfekt ohne Stammabstufung&quot;">​</a></h2><p>Perfekt Typ I (ohne Stammabstufung) haben Wurzeln der Typen:</p><ul><li>(Konsonant)-Konsonant-Langvokal-Konsonant</li><li>(Konsonant)-Konsonant-Vokal-Konsonant-Konsonant</li><li>a-Konsonant</li><li>ā-Konsonant</li></ul><p>Beispiele:</p><blockquote><table tabindex="0"><thead><tr><th>Wurzel</th><th>3.sg.Perf.</th><th>3.pl.Perf.</th></tr></thead><tbody><tr><td>बन्ध् 9P</td><td>बबन्ध</td><td></td></tr><tr><td>ba-bandh-a</td><td>बबन्धुर्</td><td></td></tr><tr><td>जीव् 1P</td><td>जिजीव</td><td>जिजीवुर्</td></tr><tr><td>आप् 5P</td><td>आप</td><td></td></tr><tr><td>a + āp-a</td><td>आपुर्</td><td></td></tr><tr><td>अस् 2P &quot;sein&quot;</td><td></td><td></td></tr><tr><td>अस् 4 &quot;werfen&quot;</td><td>आस</td><td></td></tr><tr><td>a + as-a</td><td>आसुर्</td><td></td></tr><tr><td>अश्</td><td>आनशे</td><td></td></tr><tr><td>unregelmäßige Reduplikation!</td><td>आनशिरे</td><td></td></tr></tbody></table></blockquote><h2 id="_34-5-perfekt-ii-starker-stamm-hochstufe-schwacher-stamm-tiefstufe" tabindex="-1">34.5. Perfekt II: starker Stamm Hochstufe, schwacher Stamm Tiefstufe <a class="header-anchor" href="#_34-5-perfekt-ii-starker-stamm-hochstufe-schwacher-stamm-tiefstufe" aria-label="Permalink to &quot;34.5. Perfekt II: starker Stamm Hochstufe, schwacher Stamm Tiefstufe&quot;">​</a></h2><p>Gebildet von Verben des Typus:</p><ul><li>(Konsonant)-(Konsonant)-i/u/ṛ/ḷ-Konsonant</li></ul><p>Bildung:</p><ul><li>starker Stamm: Hochstufe</li><li>schwacher Stamm: Tiefstufe</li></ul><p>Beispiele:</p><blockquote><table tabindex="0"><thead><tr><th>Wurzel</th><th>3.sg.Perf.P</th><th>3.pl.Perf.P</th><th>3.sg.Perf.Ā</th><th>3.pl.Perf.Ā</th></tr></thead><tbody><tr><td>भिद्</td><td>बिभेद</td><td>बिभिदुर्</td><td>बिभिदे</td><td>बिभिदिरे</td></tr><tr><td>इस्</td><td>इयेष</td><td>ईषुर्</td><td></td><td></td></tr><tr><td>मुच्</td><td>मुमोच</td><td>मुमुचुर्</td><td>मुमुचे</td><td>मुमुचिरे</td></tr><tr><td>वृत्</td><td></td><td></td><td>ववृते</td><td>ववृतिरे</td></tr><tr><td>कॢप्</td><td></td><td></td><td>चकॢपे</td><td>चकॢपिरे</td></tr></tbody></table></blockquote><h2 id="_34-6-wortliste" tabindex="-1">34.6. Wortliste <a class="header-anchor" href="#_34-6-wortliste" aria-label="Permalink to &quot;34.6. Wortliste&quot;">​</a></h2><p>क्षिति f. = पृथ्वी = मही = भूमी</p><p>शस्य = सस्य n. sg. u. pl.: Saat, Feldfrucht, Getreide</p><p><img src="'+n+'" alt=""><br> Abb.: सस्यम्<br> [Bildquelle: Ray Witlin / World Bank. -- <a href="http://www.flickr.com/photos/worldbank/2183806492/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/worldbank/2183806492/</a>. -- Zugriff am 2008-12-27. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><p>यावत् : wie lange wie groß</p><p>तावत् : so lange, so groß</p><p>उत्तम 3: höchster</p><p>द्वीप m.n.: Insel, Kontinent</p><p><img src="'+l+'" alt=""><br> Abb.: लक्षद्वीपाः = ലക്ഷദ്വീപ് = die 100.000 (लक्ष m.n.) Inseln (Unionsterritorium)<br> [Bildquelle: CIA. Public domain]</p><p>मर्त्य 3: sterblich (zu मृ)</p><p>तिल m.: Sesam(korn) (<em>Sesamum indicum</em> L.)</p><p><img src="'+d+'" alt=""><br> Abb.: तिलाः<br> [Bildquelle: Wikipedia. Public domain]</p><p><img src="'+o+'" alt=""><br> Abb.: <em>Sesamum indicum</em> L.<br> [Bildquelle: Franz Xaver / Wikipedia. GNU FDLicense]</p><p>स्वर्ण n.: (schönfarbig =) Gold</p><p><img src="'+s+'" alt=""><br> Abb.: स्वर्णम्<br> Harmandir Sahib = ਹਰਿਮੰਦਰ ਸਾਹਿਬ, Amritsar = ਅੰਮ੍ਰਿਤਸਰ<br> [Bildquelle: Wikipedia. GNU FDLicense]</p><p>निकेतन n.: Wohnstatt, Tempel</p><p>कोटि f.: Spitze; 10 Millionen</p><p>श्रेष्ठ 3: bester</p><p>तल m.n.: Ebene, Fläche</p><p>ऋषभ m.: Stier</p><p><img src="'+u+'" alt=""><br> Abb.: ऋषभः<br> Chamundi-Hills<br> [Bildquelle: Luna Park. -- <a href="http://www.flickr.com/photos/lunapark/2124083737/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/lunapark/2124083737/</a>. -- Zugriff am 2008-12-27. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><p>यम् 1P यच्छति : zurückhalten, halten, darbieten, gewähren</p><p>यम् प्र 1 P प्रयच्छति : hinhalten, anbieten, abliefern</p><p>या 2P याति : gehen, fahren</p><p>कन्या f.: Mädchen, Jungfrau</p><h2 id="_34-7-ubung" tabindex="-1">34.7. Übung <a class="header-anchor" href="#_34-7-ubung" aria-label="Permalink to &quot;34.7. Übung&quot;">​</a></h2><p>Bilden Sie zu folgenden Verbformen die in Person, Zahl und Genus entprechenden Perfektformen:</p><ol><li>रक्षिष्यन्ति</li><li>स्रक्ष्यति</li><li>सिञ्चते</li><li>वर्तते</li><li>प्रवेक्ष्यति</li><li>भनक्ति</li><li>लुभ्यन्ति</li><li>रुन्धते</li><li>रोदिति</li><li>बध्नाति</li><li>युध्यन्ते</li><li>युङ्क्ते</li><li>मुह्यन्ति</li><li>मुञ्चते</li><li>जीवन्ति</li><li>भोक्ष्यते</li><li>आप्नुवन्ति</li><li>भिन्त्ते</li><li>भोत्स्यन्ते</li><li>नर्तिष्यति</li><li>अश्नाति</li><li>द्वेष्टि</li><li>पश्यन्ति</li><li>दुग्धे</li><li>सन्ति</li><li>आदेक्ष्यन्ति</li><li>छिनत्ति</li><li>क्रुध्यति</li><li>अस्यति</li><li>कुप्यन्ति</li><li>इच्छन्ति</li></ol><h2 id="_34-8-ubersetzungsubung" tabindex="-1">34.8. Übersetzungsübung <a class="header-anchor" href="#_34-8-ubersetzungsubung" aria-label="Permalink to &quot;34.8. Übersetzungsübung&quot;">​</a></h2><p>Übersetzen Sie folgenden Text aus dem पद्मपुराण über Gaben an Brahmanen:</p><p>क्षितिं सशस्यां यो दद्याद्ब्राह्मणाय द्विजोत्तम ।<br> विष्णुलोके सुखं भुङ्क्ते यावदिन्द्राश्चतुर्दश ॥१॥<br> सप्तद्वीपां महीं दत्त्वा यत्पुण्यं प्राप्यते द्विज ।<br> तत्पुण्यं प्राप्नुयान्मर्त्यो धेनुं यच्छन्द्विजातये ॥२॥<br> तिलप्रमाणं स्वर्णं यो ब्राह्मणाय प्रयच्छति ।<br> हरिनिकेतनं याति युक्तं कोटिकुलैरपि ॥३॥<br> सालङ्कारां द्विजश्रेष्ठ कन्यां यच्छति यो नरः ।<br> स गच्छेद्ब्रह्मसदनं पुनर्जन्म न विद्यते ॥४॥<br> अन्नं वारि द्विजश्रेष्ठ येन दत्तम् महीतले ।<br> तेन दत्तानि दानानि सर्वाणि च द्विजर्षभ ॥५॥</p><p>Erklärungen:</p><p>Vokativ sg. der Maskulina / Neutra auf -a lautet auf -a: z.B. देव &quot;Gott!&quot;</p><p>चतुर्दश vierzehn</p><p>सप्त sieben</p><p>जन्म Nom./Akk. sg. zu जन्मन् n. Geburt</p><p>सर्व 3 &quot;alle, ganz&quot; (dekliniert nach Pronominaldeklination)</p><p><img src="'+p+'" alt=""><br> Abb.: सालङ्कारां द्विजश्रेष्ठ कन्यां यच्छति यो नरः ।<br> स गच्छेद्ब्रह्मसदनं पुनर्जन्म न विद्यते ॥४॥<br> [Bildquelle: BriceFR. -- <a href="http://www.flickr.com/photos/bricecanonne/1350452995/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/bricecanonne/1350452995/</a>. -- Zugriff am 2008-12-27. -- <a href="http://creativecommons.org/licenses/by-nc-sa/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, share alike)]</p>',98)])])}const q=t(h,[["render",b]]);export{z as __pageData,q as default};
